// SaveLock service worker — generated by scripts/generate-sw.mjs at build time.
// Strategy: precache the whole built site on install, then serve cache-first.
// A new deploy produces a new cache version; old caches are dropped on activate.

const CACHE = 'savelock-__CACHE_VERSION__';
const PRECACHE = __PRECACHE_MANIFEST__;

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches
      .open(CACHE)
      .then((cache) =>
        cache.addAll(PRECACHE.map((p) => new URL(p, self.registration.scope).toString()))
      )
      .then(() => self.skipWaiting())
  );
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches
      .keys()
      .then((keys) =>
        Promise.all(keys.filter((k) => k !== CACHE).map((k) => caches.delete(k)))
      )
      .then(() => self.clients.claim())
  );
});

self.addEventListener('fetch', (event) => {
  const req = event.request;
  if (req.method !== 'GET') return;
  const url = new URL(req.url);
  if (url.origin !== self.location.origin) return;

  // ignoreVary matters: servers send "Vary: Origin" / "Vary: Accept-Encoding",
  // and module-script requests carry different headers than the precache fetch.
  const opts = { ignoreSearch: true, ignoreVary: true };

  event.respondWith(
    caches
      .match(req, opts)
      .then((hit) => {
        if (hit) return hit;
        // "/goals" may be cached as "/goals/"
        if (!url.pathname.endsWith('/')) {
          return caches.match(new URL(url.pathname + '/', url.origin).toString(), opts);
        }
      })
      .then(
        (hit) =>
          hit ||
          fetch(req)
            .then((res) => {
              if (res.ok && res.type === 'basic') {
                const copy = res.clone();
                caches.open(CACHE).then((cache) => cache.put(req, copy));
              }
              return res;
            })
            .catch(() => {
              if (req.mode === 'navigate') {
                return caches.match(new URL('./', self.registration.scope).toString(), opts);
              }
            })
      )
  );
});
